import React from "react"
import '../styles/MainStyles.css';
import { useState } from 'react';
import { observer } from "mobx-react";
import { makeObservable, observable, action, computed } from "mobx";
import SignInVM from "./SignInVM";
import { ActualState } from "../../Domain/States/ActualState";



export const SignIn = observer(({setShowing, onToggleAuth}) => {

    const { actualState, signInState, updateSignInState } = SignInVM

    return(
        <div className="formsign">
            <div className="titleform">
                Не узнаем ваши лапки <br/>
                Авторизируйтесь
            </div>
            <div className="input-group">
                <input type="text" className="input-field" placeholder="Логин или Email" value={signInState.email} onChange={(e) => {updateSignInState({
                    ...signInState,
                    email: e.target.value 
                    })}}/>
                <input type="text" className="input-field" placeholder="Пароль" value={signInState.password} onChange={(e) => {updateSignInState({
                    ...signInState, 
                    password: e.target.value})}}/>
                {actualState === ActualState.Error && (<button class="button-style">Войти</button>)}
            </div>
            <div className="registNav">
                <span>Ещё нет аккаунта? </span>
                <a
                className="create-account-link"
                onClick={(e) => { onToggleAuth(false)
                }}>
                    Создать
                </a>
            </div>
        </div>
    )
})
